long long solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    // Precompute popcount-depth for each number in nums
    std::vector<int> popcount_depths;
    for (long long num : nums) {
        int depth = 0;
        long long current = num;
        while (current > 0) {
            current = __builtin_popcountll(current);
            depth++;
        }
        popcount_depths.push_back(depth);
    }

    // Create a 2D array to store the count of each depth in a range
    // Since k can be up to 5, we can use a 2D array of size n x 6
    std::vector<std::vector<int>> freq(n, std::vector<int>(6, 0));
    for (int i = 0; i < n; ++i) {
        freq[i][popcount_depths[i]] = 1;
    }

    // Build prefix sums for each depth
    std::vector<std::vector<int>> prefix(n, std::vector<int>(6, 0));
    for (int i = 0; i < n; ++i) {
        for (int k = 0; k < 6; ++k) {
            prefix[i][k] = (i > 0 ? prefix[i - 1][k] : 0) + freq[i][k];
        }
