                }
            }
            answer.push_back(res);
        } else {
            int idx = query[1], val = query[2];
            // Update the value and its popcount-depth
            long long old_val = nums[idx];
            int old_depth = popcount_depths[idx];
            int new_depth = 0;
            long long current = val;
            while (current > 0) {
                current = __builtin_popcountll(current);
                new_depth++;
            }

            // Update the frequency array
            freq[idx][old_depth] -= 1;
            freq[idx][new_depth] += 1;

            // Update the popcount_depths
            popcount_depths[idx] = new_depth;

